export interface LabEnvironment {
  projectId: string;
  username: string;
  region: string;
  zone: string;
}

export interface LabTask {
  id: number;
  title: string;
  description: string;
  commands: string[];
  framework: 'bash' | 'terraform' | 'gcloud' | 'python';
  status: 'pending' | 'completed';
}

export interface LabAnalysis {
  labName: string;
  strategy: string;
  tasks: LabTask[];
  estimatedTime: string;
}

export interface CredlyProfile {
  name: string;
  badgeCount: number;
  isVerified: boolean;
}

import { GoogleGenAI, Type } from "@google/genai";
import { LabEnvironment, LabAnalysis } from "../types";

export const analyzeLabInstructions = async (
  instructions: string,
  env: LabEnvironment
): Promise<LabAnalysis> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

  const prompt = `
    Analyze these Google Cloud Skills Boost lab instructions and environment variables.
    Environment:
    Project ID: ${env.projectId}
    Username: ${env.username}
    Region: ${env.region}
    Zone: ${env.zone}

    Instructions:
    ${instructions}

    Generate a structured execution plan. Choose the most efficient framework (Terraform, Bash, gcloud SDK) for each task.
    Ensure ALL commands use the provided environment variables (Project ID, Region, Zone) specifically.
    If multiple resources are created, aim for scriptable automation.
  `;

  const response = await ai.models.generateContent({
    model: "gemini-3-pro-preview",
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          labName: { type: Type.STRING },
          strategy: { type: Type.STRING },
          estimatedTime: { type: Type.STRING },
          tasks: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                id: { type: Type.INTEGER },
                title: { type: Type.STRING },
                description: { type: Type.STRING },
                commands: {
                  type: Type.ARRAY,
                  items: { type: Type.STRING }
                },
                framework: { 
                    type: Type.STRING,
                    description: "Options: bash, terraform, gcloud, python"
                },
                status: { type: Type.STRING }
              },
              required: ["id", "title", "commands", "framework"]
            }
          }
        },
        required: ["labName", "strategy", "tasks"]
      },
    },
  });

  try {
    return JSON.parse(response.text || '{}');
  } catch (e) {
    console.error("Failed to parse Gemini response", e);
    throw new Error("Invalid response format from AI");
  }
};

export const generateLabSummary = async (
  analysis: LabAnalysis,
  env: LabEnvironment
): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

  const prompt = `
    Create a professional summary of the completed lab: ${analysis.labName}.
    Environment used: Project ${env.projectId} in ${env.region}.

    The summary should explain:
    1. Key architectural components created.
    2. Challenges overcome.
    3. How these skills translate to Google Cloud Professional Cloud Architect or Engineer roles.

    Keep it concise for an advanced user.
  `;

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: prompt
  });

  return response.text || "Summary generation failed.";
};

