import React, { useState } from 'react';

interface Props {
  commands: string[];
  framework: string;
}

const TerminalOutput: React.FC<Props> = ({ commands, framework }) => {
  const [copied, setCopied] = useState(false);

  const fullCommand = commands.join('\n');

  const handleCopy = () => {
    navigator.clipboard.writeText(fullCommand);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  return (
    <div className="bg-gray-900 rounded-lg overflow-hidden my-4 shadow-xl border border-gray-700">
      <div className="flex items-center justify-between px-4 py-2 bg-gray-800 border-b border-gray-700">
        <div className="flex gap-1.5">
          <div className="w-3 h-3 rounded-full bg-red-500"></div>
          <div className="w-3 h-3 rounded-full bg-yellow-500"></div>
          <div className="w-3 h-3 rounded-full bg-green-500"></div>
        </div>
        <div className="text-xs text-gray-400 font-mono flex items-center gap-2">
          <span className="uppercase">{framework}</span>
          <button 
            onClick={handleCopy}
            className="hover:text-white transition-colors"
          >
            {copied ? 'Copied!' : 'Copy'}
          </button>
        </div>
      </div>
      <div className="p-4 terminal-font text-sm text-green-400 overflow-x-auto whitespace-pre">
        {commands.map((cmd, i) => (
          <div key={i} className="flex gap-4">
            <span className="text-gray-600 select-none">{(i + 1).toString().padStart(2, '0')}</span>
            <span>{cmd}</span>
          </div>
        ))}
      </div>
    </div>
  );
};

export default TerminalOutput;

