import { GoogleGenAI, Type } from "@google/genai";
import { LabEnvironment, LabAnalysis, LabTask, LabFix } from "../types";

export const analyzeLabInstructions = async (
  instructions: string,
  env: LabEnvironment
): Promise<LabAnalysis> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

  const prompt = `
    Analyze these Google Cloud Skills Boost lab instructions and environment variables.
    Environment:
    Project ID: ${env.projectId}
    Username: ${env.username}
    Region: ${env.region}
    Zone: ${env.zone}

    Instructions:
    ${instructions}

    Generate a structured execution plan. Choose the most efficient framework (Terraform, Bash, gcloud SDK) for each task.
    Ensure ALL commands use the provided environment variables (Project ID, Region, Zone) specifically.
    If multiple resources are created, aim for scriptable automation.
  `;

  const response = await ai.models.generateContent({
    model: "gemini-3-pro-preview",
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          labName: { type: Type.STRING },
          strategy: { type: Type.STRING },
          estimatedTime: { type: Type.STRING },
          tasks: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                id: { type: Type.INTEGER },
                title: { type: Type.STRING },
                description: { type: Type.STRING },
                commands: {
                  type: Type.ARRAY,
                  items: { type: Type.STRING }
                },
                framework: { 
                    type: Type.STRING,
                    description: "Options: bash, terraform, gcloud, python"
                },
                status: { type: Type.STRING }
              },
              required: ["id", "title", "commands", "framework"]
            }
          }
        },
        required: ["labName", "strategy", "tasks"]
      },
    },
  });

  try {
    return JSON.parse(response.text || '{}');
  } catch (e) {
    console.error("Failed to parse Gemini response", e);
    throw new Error("Invalid response format from AI");
  }
};

export const troubleshootTask = async (
  task: LabTask,
  errorOutput: string,
  env: LabEnvironment
): Promise<LabFix> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

  const prompt = `
    The user encountered an error while executing task: "${task.title}".
    Original Commands:
    ${task.commands.join('\n')}

    Error Output from Terminal:
    ${errorOutput}

    Environment Context:
    Project: ${env.projectId}, Region: ${env.region}, Zone: ${env.zone}

    Analyze the error output. Identify common GCP issues like:
    1. Missing API enablement.
    2. Missing IAM permissions (especially service agent roles for GCS/PubSub).
    3. Resource naming conflicts.
    4. Quota limits.

    Provide a remediation plan and corrected commands to resolve this specific error.
  `;

  const response = await ai.models.generateContent({
    model: "gemini-3-pro-preview",
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          remediation: { type: Type.STRING },
          commands: {
            type: Type.ARRAY,
            items: { type: Type.STRING }
          }
        },
        required: ["remediation", "commands"]
      }
    }
  });

  try {
    return JSON.parse(response.text || '{}');
  } catch (e) {
    console.error("Troubleshooting failed", e);
    throw new Error("Failed to generate a fix.");
  }
};

export const generateLabSummary = async (
  analysis: LabAnalysis,
  env: LabEnvironment
): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

  const prompt = `
    Create a professional summary of the completed lab: ${analysis.labName}.
    Environment used: Project ${env.projectId} in ${env.region}.

    The summary should explain:
    1. Key architectural components created.
    2. Challenges overcome (mention if any troubleshooting was needed).
    3. How these skills translate to Google Cloud Professional Cloud Architect or Engineer roles.

    Keep it concise for an advanced user.
  `;

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: prompt
  });

  return response.text || "Summary generation failed.";
};

import React, { useState } from 'react';

interface Props {
  commands: string[];
  framework: string;
  variant?: 'default' | 'fix';
}

const TerminalOutput: React.FC<Props> = ({ commands, framework, variant = 'default' }) => {
  const [copied, setCopied] = useState(false);

  const fullCommand = commands.join('\n');

  const handleCopy = () => {
    navigator.clipboard.writeText(fullCommand);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  const isFix = variant === 'fix';

  return (
    <div className={`rounded-lg overflow-hidden my-4 shadow-xl border ${isFix ? 'bg-amber-950 border-amber-600' : 'bg-gray-900 border-gray-700'}`}>
      <div className={`flex items-center justify-between px-4 py-2 border-b ${isFix ? 'bg-amber-900 border-amber-700' : 'bg-gray-800 border-gray-700'}`}>
        <div className="flex gap-1.5">
          {isFix ? (
            <span className="text-[10px] font-bold text-amber-400 uppercase tracking-tighter flex items-center gap-1">
              <svg className="w-3 h-3" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M11.3 1.046A1 1 0 0112 2v5h4a1 1 0 01.82 1.573l-7 10A1 1 0 018 18v-5H4a1 1 0 01-.82-1.573l7-10a1 1 0 011.12-.38z" clipRule="evenodd"></path></svg>
              Corrected Script
            </span>
          ) : (
            <>
              <div className="w-3 h-3 rounded-full bg-red-500"></div>
              <div className="w-3 h-3 rounded-full bg-yellow-500"></div>
              <div className="w-3 h-3 rounded-full bg-green-500"></div>
            </>
          )}
        </div>
        <div className="text-xs text-gray-400 font-mono flex items-center gap-2">
          <span className="uppercase">{framework}</span>
          <button 
            onClick={handleCopy}
            className="hover:text-white transition-colors"
          >
            {copied ? 'Copied!' : 'Copy'}
          </button>
        </div>
      </div>
      <div className={`p-4 terminal-font text-sm overflow-x-auto whitespace-pre ${isFix ? 'text-amber-200' : 'text-green-400'}`}>
        {commands.map((cmd, i) => (
          <div key={i} className="flex gap-4">
            <span className={`${isFix ? 'text-amber-700' : 'text-gray-600'} select-none`}>{(i + 1).toString().padStart(2, '0')}</span>
            <span>{cmd}</span>
          </div>
        ))}
      </div>
    </div>
  );
};

export default TerminalOutput;

