import { GoogleGenAI, Type } from "@google/genai";
import { LabEnvironment, LabAnalysis, LabTask, LabFix } from "../types";

export const analyzeLabInstructions = async (
  instructions: string,
  env: LabEnvironment
): Promise<LabAnalysis> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

  const prompt = `
    Analyze these Google Cloud Skills Boost lab instructions and environment variables.
    Environment:
    Project ID: ${env.projectId}
    Username: ${env.username}
    Region: ${env.region}
    Zone: ${env.zone}

    Instructions:
    ${instructions}

    REQUIREMENTS:
    1. Task 1 MUST ALWAYS be "IAM & Service Account Verification". It should include gcloud commands to:
       - List active account and project.
       - Check current IAM policy for the student user.
       - Identify and verify necessary Service Accounts (e.g., Compute, App Engine, Eventarc).
       - GRANT necessary roles (e.g., roles/eventarc.eventReceiver, roles/pubsub.publisher, roles/iam.serviceAccountTokenCreator) to the relevant service agents if the lab involves triggers, functions, or cross-service communication.
    2. Generate a structured execution plan for the remaining tasks.
    3. Choose the most efficient framework (Terraform, Bash, gcloud SDK).
    4. Ensure ALL commands use the provided environment variables.
  `;

  const response = await ai.models.generateContent({
    model: "gemini-3-pro-preview",
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          labName: { type: Type.STRING },
          strategy: { type: Type.STRING },
          estimatedTime: { type: Type.STRING },
          tasks: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                id: { type: Type.INTEGER },
                title: { type: Type.STRING },
                description: { type: Type.STRING },
                commands: {
                  type: Type.ARRAY,
                  items: { type: Type.STRING }
                },
                framework: { 
                    type: Type.STRING,
                    description: "Options: bash, terraform, gcloud, python"
                },
                status: { type: Type.STRING }
              },
              required: ["id", "title", "commands", "framework"]
            }
          }
        },
        required: ["labName", "strategy", "tasks"]
      },
    },
  });

  try {
    return JSON.parse(response.text || '{}');
  } catch (e) {
    console.error("Failed to parse Gemini response", e);
    throw new Error("Invalid response format from AI");
  }
};

