            <div className="bg-blue-600 p-2 rounded-lg">
              <svg className="w-6 h-6 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19.428 15.428a2 2 0 00-1.022-.547l-2.387-.477a6 6 0 00-3.86.517l-.318.158a6 6 0 01-3.86.517L6.05 15.21a2 2 0 00-1.806.547M8 4h8l-1 1v5.172a2 2 0 00.586 1.414l5 5c1.26 1.26.367 3.414-1.415 3.414H4.828c-1.782 0-2.674-2.154-1.414-3.414l5-5A2 2 0 009 10.172V5L8 4z"></path></svg>
            </div>
            <h1 className="text-xl font-bold tracking-tight text-slate-800">CloudLab Automator <span className="text-blue-600">Pro</span></h1>
          </div>
          <div className="flex items-center gap-4">
            <div className="hidden md:flex flex-col items-end">
              <span className="text-xs font-semibold text-slate-500 uppercase tracking-wider">Advanced User</span>
              <span className="text-sm font-bold text-slate-800">{profile.name}</span>
            </div>
            <div className="h-10 w-10 rounded-full bg-blue-100 border border-blue-200 flex items-center justify-center font-bold text-blue-600">
              {profile.badgeCount}+
            </div>
          </div>
        </div>
      </header>

      <main className="max-w-7xl mx-auto px-4 mt-8 grid grid-cols-1 lg:grid-cols-3 gap-8">
        {/* Left Column */}
        <div className="lg:col-span-1 space-y-6">
          <section className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
            <h2 className="text-lg font-bold mb-4 flex items-center gap-2">
              <span className="p-1 bg-slate-100 rounded text-slate-600">01</span> 
              Environment Data
            </h2>
            <div className="space-y-4">
              <div>
                <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Project ID</label>
                <input 
                  name="projectId"
                  value={env.projectId}
                  onChange={handleEnvChange}
                  className="w-full px-3 py-2 bg-slate-50 border rounded-md focus:ring-2 focus:ring-blue-500 outline-none" 
                  placeholder="e.g. qwiklabs-gcp-00-abc123"
                />
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Region</label>
                  <input name="region" value={env.region} onChange={handleEnvChange} className="w-full px-3 py-2 bg-slate-50 border rounded-md focus:ring-2 focus:ring-blue-500 outline-none" placeholder="us-central1" />
                </div>
                <div>
                  <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Zone</label>
                  <input name="zone" value={env.zone} onChange={handleEnvChange} className="w-full px-3 py-2 bg-slate-50 border rounded-md focus:ring-2 focus:ring-blue-500 outline-none" placeholder="us-central1-a" />
