              <span className="p-1 bg-slate-100 rounded text-slate-600">02</span> 
              Lab Instructions
            </h2>
            <textarea 
              value={instructions}
              onChange={(e) => setInstructions(e.target.value)}
              className="w-full h-64 px-3 py-2 bg-slate-50 border rounded-md focus:ring-2 focus:ring-blue-500 outline-none text-sm leading-relaxed"
